public class BMICalculator {
    public static void main(String[] args) {
        double weightKg = 75.5;
        double heightM = 1.75;

        double bmi = weightKg / (heightM * heightM);
        String category;

        if (bmi < 18.5) {
            category = "Underweight";
        } else if (bmi < 25.0) {
            category = "Normal";
        } else if (bmi < 30.0) {
            category = "Overweight";
        } else {
            category = "Obese";
        }

        System.out.println("BMI: " + bmi);
        System.out.println("Category: " + category);
    }
}

