public class ShippingCalculator {
    public static void main(String[] args) {
        double orderTotal = 2500.0;
        double weightKg = 3.5;
        String destinationType = "Metro";
        boolean isPrimeMember = true;
        String requestedSpeed = "Standard";

        double finalCost;
        boolean freeShipping = false;

        // Rule 1: Free shipping for Prime members with standard speed and qualifying order
        if (isPrimeMember && orderTotal >= 500 && requestedSpeed.equals("Standard")) {
            freeShipping = true;
            finalCost = 0.0;
        } else {
            // Rule 2: Base cost by destination
            double baseCost = switch (destinationType) {
                case "Metro" -> 50.0;
                case "Tier-2" -> 100.0;
                case "Tier-3" -> 150.0;
                case "Remote" -> 250.0;
                default -> 100.0;
            };

            // Rule 3: Weight surcharge
            if (weightKg > 2.0 && weightKg <= 5.0) {
                baseCost += 50;
            } else if (weightKg > 5.0) {
                baseCost += 150;
            }

            // Rule 4: Speed multiplier
            if (requestedSpeed.equals("Express")) {
                baseCost *= 2;
            } else if (requestedSpeed.equals("Overnight")) {
                baseCost *= 3;
            }

            finalCost = baseCost;
        }

        // Output
        System.out.println("=========================================");
        System.out.println("           SHIPPING ESTIMATE");
        System.out.println("=========================================");
        System.out.println("Order Total:      ₹" + orderTotal);
        System.out.println("Weight:           " + weightKg + " kg");
        System.out.println("Destination:      " + destinationType);
        System.out.println("Prime Member:     " + isPrimeMember);
        System.out.println("Requested Speed:  " + requestedSpeed);
        System.out.println("-----------------------------------------");
        System.out.println("Free Shipping:    " + freeShipping);
        System.out.println("Final Cost:       ₹" + finalCost);
        System.out.println("=========================================");
    }
}
